<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body{
    margin:0;
    background:#111;
    color:#eee;
    font-family:Arial,Helvetica,sans-serif;
    display:flex;
    flex-direction:column;
    align-items:center;
    min-height:100vh;
    user-select:none;
  }
  #controls{
    margin:10px;
    display:flex;
    gap:5px;
    flex-wrap:wrap;
    justify-content:center;
  }
  button{
    background:#333;
    border:none;
    color:#eee;
    padding:8px 12px;
    cursor:pointer;
    border-radius:4px;
    min-width:70px;
  }
  button.active{
    background:#555;
  }
  button:hover{
    background:#444;
  }
  canvas{
    background:#000;
    image-rendering:pixelated;
    border:2px solid #555;
  }
</style>
</head>
<body>
<div id="controls">
  <button id="mat-sand"   class="active">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sand" width="400" height="400"></canvas>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');

  const CELL_SIZE = 5; // 400/80 =5
  const W = Math.floor(canvas.width / CELL_SIZE);
  const H = Math.floor(canvas.height / CELL_SIZE);

  const MAT = {
    empty:0,
    sand:1,
    water:2,
    wall:3,
    acid:4
  };
  const COLORS = {
    0:'#000000',
    1:'#c2b280',
    2:'#4da6ff',
    3:'#777777',
    4:'#00ff00'
  };

  // grid as Uint8Array
  const grid = new Uint8Array(W*H);
  const next = new Uint8Array(W*H); // temp for swaps

  // UI state
  let curMat = MAT.sand;
  const btnMap = {
    'mat-sand':'sand',
    'mat-water':'water',
    'mat-wall':'wall',
    'mat-acid':'acid',
    'mat-empty':'empty'
  };
  for(const id in btnMap){
    const btn=document.getElementById(id);
    btn.addEventListener('click',()=>{ setMaterial(btnMap[id]); });
  }
  document.getElementById('clear').addEventListener('click',()=>{ clearGrid(); });

  function setMaterial(name){
    curMat = MAT[name];
    document.querySelectorAll('#controls button').forEach(b=>b.classList.remove('active'));
    document.getElementById('mat-'+name).classList.add('active');
  }

  // painting
  let mouseDown = false;
  canvas.addEventListener('mousedown',e=>{ mouseDown=true; paint(e); });
  canvas.addEventListener('mousemove',e=>{ if(mouseDown) paint(e); });
  window.addEventListener('mouseup',()=>{ mouseDown=false; });

  function paint(e){
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX-rect.left)/CELL_SIZE);
    const y = Math.floor((e.clientY-rect.top)/CELL_SIZE);
    if(x>=0&&x<W&&y>=0&&y<H){
      setCell(x,y,curMat);
    }
  }

  // simulation step
  function step(){
    // copy grid to next for reference
    next.set(grid);
    // process bottom-up
    for(let y=H-2; y>=0; y--){ // skip bottom row (static)
      for(let x=0; x<W; x++){
        const idx = y*W + x;
        const type = grid[idx];
        if(type===MAT.sand){
          moveSand(x,y);
        }else if(type===MAT.water){
          moveWater(x,y);
        }else if(type===MAT.acid){
          moveAcid(x,y);
        }
      }
    }
    // draw
    draw();
  }

  function moveSand(x,y){
    const idx = y*W + x;
    // try down
    if(canMoveInto(x,y+1)){
      swap(idx, (y+1)*W + x);
      return;
    }
    // slide
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx = x+d, ny = y+1;
      if(inBounds(nx,ny) && canMoveInto(nx,ny)){
        swap(idx, ny*W + nx);
        return;
      }
    }
  }

  function moveWater(x,y){
    const idx = y*W + x;
    // down
    if(canMoveInto(x,y+1)){
      swap(idx, (y+1)*W + x);
      return;
    }
    // spread
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx = x+d;
      if(inBounds(nx,y) && canMoveInto(nx,y)){
        swap(idx, y*W + nx);
        return;
      }
    }
  }

  function moveAcid(x,y){
    const idx = y*W + x;
    // dissolve neighbours first
    const neighbours = [
      [0,1],[ -1,0],[1,0],[ -1,1],[1,1]
    ];
    for(const [dx,dy] of neighbours){
      const nx=x+dx, ny=y+dy;
      if(inBounds(nx,ny)){
        const nIdx=ny*W+nx;
        const nType=grid[nIdx];
        if(nType===MAT.sand||nType===MAT.wall){
          // dissolve: remove target, optionally also self
          setCell(nx,ny,MAT.empty);
          // 50% chance acid disappears
          if(Math.random()<0.5) { setCell(x,y,MAT.empty); return; }
        }
      }
    }
    // then move like water
    if(canMoveInto(x,y+1)){
      swap(idx, (y+1)*W + x);
      return;
    }
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx = x+d;
      if(inBounds(nx,y) && canMoveInto(nx,y)){
        swap(idx, y*W + nx);
        return;
      }
    }
  }

  function canMoveInto(x,y){
    if(!inBounds(x,y)) return false;
    const target = grid[y*W+x];
    return target===MAT.empty || target===MAT.water || target===MAT.acid;
  }
  function inBounds(x,y){
    return x>=0 && x<W && y>=0 && y<H;
  }
  function swap(i1,i2){
    const t = grid[i1];
    grid[i1]=grid[i2];
    grid[i2]=t;
  }
  function setCell(x,y,m){
    grid[y*W+x]=MAT[m]!==undefined?MAT[m]:m;
  }

  function draw(){
    const img = ctx.createImageData(W,H);
    const data = img.data;
    for(let i=0;i<grid.length;i++){
      const c = COLORS[grid[i]];
      const r=parseInt(c.slice(1,3),16);
      const g=parseInt(c.slice(3,5),16);
      const b=parseInt(c.slice(5,7),16);
      const p=i*4;
      data[p]=r; data[p+1]=g; data[p+2]=b; data[p+3]=255;
    }
    // scale to canvas size
    const off = ctx.createImageData(W,H);
    ctx.putImageData(img,0,0);
    ctx.drawImage(canvas,0,0,canvas.width,canvas.height);
  }

  function clearGrid(){
    grid.fill(MAT.empty);
    draw();
  }

  // animation loop
  function loop(){
    step();
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);

  // expose API
  window.sim = {
    w:W, h:H,
    tick(n){
      for(let i=0;i<n;i++) step();
    },
    get(x,y){
      if(!inBounds(x,y)) return null;
      const v=grid[y*W+x];
      return Object.keys(MAT).find(k=>MAT[k]===v);
    },
    set(x,y,material){
      if(!inBounds(x,y)) return;
      const v=MAT[material];
      if(v!==undefined) grid[y*W+x]=v;
    },
    clear:clearGrid
  };
})();
</script>
</body>
</html>
